from pathlib import Path

def replace(path, old, new):
    target = Path(path)
    text = target.read_text()
    if old not in text:
        raise SystemExit(f'Expected text not found in {path}: {old[:120]!r}')
    target.write_text(text.replace(old, new, 1))

def write(path, content):
    target = Path(path)
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content)

write('apps/tenant/assessments/migrations/0004_grading_profiles_report_rules.py', '\nfrom decimal import Decimal\n\nimport django.core.validators\nimport django.db.models.deletion\nfrom django.db import migrations, models\n\n\nclass Migration(migrations.Migration):\n    dependencies = [\n        ("academics", "0003_gradingscale_stream_graderange"),\n        ("assessments", "0003_configurable_assessment_framework"),\n        ("education_frameworks", "0001_initial"),\n        ("orgsettings", "0006_merge_20260624_1447"),\n    ]\n\n    operations = [\n        migrations.CreateModel(\n            name="GradingProfile",\n            fields=[\n                ("id", models.BigAutoField(auto_created=True, primary_key=True, serialize=False, verbose_name="ID")),\n                ("code", models.CharField(max_length=48, unique=True)),\n                ("name", models.CharField(max_length=128)),\n                ("description", models.TextField(blank=True)),\n                (\n                    "overall_aggregation",\n                    models.CharField(\n                        choices=[\n                            ("MEAN", "Mean of completed course results"),\n                            ("CREDIT_WEIGHTED", "Credit-weighted mean"),\n                        ],\n                        default="MEAN",\n                        max_length=24,\n                    ),\n                ),\n                (\n                    "incomplete_result_policy",\n                    models.CharField(\n                        choices=[\n                            ("EXCLUDE", "Exclude incomplete courses from the overall result"),\n                            ("ZERO", "Treat incomplete courses as zero"),\n                            ("INCOMPLETE", "Keep the report incomplete until every course is complete"),\n                        ],\n                        default="EXCLUDE",\n                        max_length=16,\n                    ),\n                ),\n                (\n                    "pass_percentage",\n                    models.DecimalField(\n                        decimal_places=2,\n                        default=50,\n                        max_digits=5,\n                        validators=[\n                            django.core.validators.MinValueValidator(Decimal("0")),\n                            django.core.validators.MaxValueValidator(Decimal("100")),\n                        ],\n                    ),\n                ),\n                (\n                    "promotion_percentage",\n                    models.DecimalField(\n                        blank=True,\n                        decimal_places=2,\n                        max_digits=5,\n                        null=True,\n                        validators=[\n                            django.core.validators.MinValueValidator(Decimal("0")),\n                            django.core.validators.MaxValueValidator(Decimal("100")),\n                        ],\n                    ),\n                ),\n                ("minimum_passed_courses", models.PositiveSmallIntegerField(blank=True, null=True)),\n                (\n                    "decimal_places",\n                    models.PositiveSmallIntegerField(\n                        default=2,\n                        validators=[django.core.validators.MaxValueValidator(4)],\n                    ),\n                ),\n                ("priority", models.IntegerField(default=0)),\n                ("is_default", models.BooleanField(default=False)),\n                ("is_active", models.BooleanField(default=True)),\n                ("settings", models.JSONField(blank=True, default=dict)),\n                ("created_at", models.DateTimeField(auto_now_add=True)),\n                ("updated_at", models.DateTimeField(auto_now=True)),\n                (\n                    "academic_term",\n                    models.ForeignKey(\n                        blank=True,\n                        null=True,\n                        on_delete=django.db.models.deletion.SET_NULL,\n                        related_name="grading_profiles",\n                        to="academics.academicterm",\n                    ),\n                ),\n                (\n                    "campus",\n                    models.ForeignKey(\n                        blank=True,\n                        null=True,\n                        on_delete=django.db.models.deletion.SET_NULL,\n                        related_name="grading_profiles",\n                        to="orgsettings.campus",\n                    ),\n                ),\n                (\n                    "grading_scale",\n                    models.ForeignKey(\n                        on_delete=django.db.models.deletion.PROTECT,\n                        related_name="grading_profiles",\n                        to="academics.gradingscale",\n                    ),\n                ),\n                (\n                    "level",\n                    models.ForeignKey(\n                        blank=True,\n                        null=True,\n                        on_delete=django.db.models.deletion.SET_NULL,\n                        related_name="grading_profiles",\n                        to="academics.level",\n                    ),\n                ),\n                (\n                    "program",\n                    models.ForeignKey(\n                        blank=True,\n                        null=True,\n                        on_delete=django.db.models.deletion.SET_NULL,\n                        related_name="grading_profiles",\n                        to="academics.program",\n                    ),\n                ),\n                (\n                    "stage",\n                    models.ForeignKey(\n                        blank=True,\n                        null=True,\n                        on_delete=django.db.models.deletion.SET_NULL,\n                        related_name="grading_profiles",\n                        to="education_frameworks.educationstage",\n                    ),\n                ),\n            ],\n            options={"ordering": ("-priority", "-is_default", "name")},\n        ),\n        migrations.CreateModel(\n            name="ReportRule",\n            fields=[\n                ("id", models.BigAutoField(auto_created=True, primary_key=True, serialize=False, verbose_name="ID")),\n                ("report_title", models.CharField(blank=True, max_length=128)),\n                ("result_label", models.CharField(default="Result", max_length=48)),\n                ("promotion_label", models.CharField(default="Progression", max_length=48)),\n                ("show_percentage", models.BooleanField(default=True)),\n                ("show_grade", models.BooleanField(default=True)),\n                ("show_remark", models.BooleanField(default=True)),\n                ("show_published_scores", models.BooleanField(default=True)),\n                ("show_assessment_details", models.BooleanField(default=True)),\n                ("show_component_breakdown", models.BooleanField(default=True)),\n                ("show_promotion_status", models.BooleanField(default=False)),\n                ("show_teacher_comments", models.BooleanField(default=True)),\n                ("show_head_comments", models.BooleanField(default=True)),\n                ("settings", models.JSONField(blank=True, default=dict)),\n                ("updated_at", models.DateTimeField(auto_now=True)),\n                (\n                    "grading_profile",\n                    models.OneToOneField(\n                        on_delete=django.db.models.deletion.CASCADE,\n                        related_name="report_rule",\n                        to="assessments.gradingprofile",\n                    ),\n                ),\n            ],\n        ),\n    ]\n')
write('apps/tenant/assessments/grading_services.py', '\nfrom __future__ import annotations\n\nfrom collections import Counter\nfrom decimal import Decimal, ROUND_HALF_UP\n\nfrom django.core.exceptions import ValidationError\nfrom django.db.models import Q\n\nfrom apps.tenant.academics.models import GradeRange, GradingScale\n\nfrom .models import GradingProfile, ReportRule\n\n\ndef _to_decimal(value, default=None):\n    if value in (None, ""):\n        return default\n    try:\n        return Decimal(str(value))\n    except Exception:\n        return default\n\n\ndef offering_level(offering):\n    if offering.class_group_id and offering.class_group.level_id:\n        return offering.class_group.level\n    if offering.course_id and offering.course.level_id:\n        return offering.course.level\n    return None\n\n\ndef offering_program(offering):\n    if offering.class_group_id and offering.class_group.program_id:\n        return offering.class_group.program\n    if offering.course_id and offering.course.program_id:\n        return offering.course.program\n    return None\n\n\ndef offering_stage(offering):\n    level = offering_level(offering)\n    if not level:\n        return None\n    try:\n        from apps.tenant.education_frameworks.models import InstitutionEducationProfile\n        from apps.tenant.education_frameworks.services import resolve_level_stage\n\n        profile = InstitutionEducationProfile.objects.filter(is_active=True).first()\n        return resolve_level_stage(level, profile) if profile else None\n    except Exception:\n        return None\n\n\ndef grading_scale_errors(scale: GradingScale) -> list[str]:\n    errors = []\n    if not scale.is_active:\n        errors.append("The grading scale is inactive.")\n    ranges = list(scale.ranges.order_by("min_score", "max_score", "pk"))\n    if not ranges:\n        return errors + ["The grading scale has no grade ranges."]\n    previous_max = None\n    for item in ranges:\n        minimum = _to_decimal(item.min_score, Decimal("0"))\n        maximum = _to_decimal(item.max_score, Decimal("0"))\n        if minimum > maximum:\n            errors.append(f"{item.grade}: minimum score exceeds maximum score.")\n            continue\n        if minimum < 0 or maximum > 100:\n            errors.append(f"{item.grade}: grade ranges must stay between 0 and 100.")\n        if previous_max is not None and minimum <= previous_max:\n            errors.append(f"{item.grade}: overlaps another grade range.")\n        previous_max = maximum\n    return errors\n\n\ndef grading_profile_errors(profile: GradingProfile) -> list[str]:\n    if not profile.grading_scale_id:\n        return ["Choose a grading scale."]\n    errors = grading_scale_errors(profile.grading_scale)\n    duplicate = GradingProfile.objects.filter(\n        campus_id=profile.campus_id,\n        stage_id=profile.stage_id,\n        level_id=profile.level_id,\n        program_id=profile.program_id,\n        academic_term_id=profile.academic_term_id,\n        priority=profile.priority,\n        is_active=True,\n    )\n    if profile.pk:\n        duplicate = duplicate.exclude(pk=profile.pk)\n    if profile.is_active and duplicate.exists():\n        errors.append("Another active grading profile has the same scope and priority.")\n    try:\n        profile.full_clean()\n    except ValidationError as exc:\n        errors.extend(exc.messages)\n    return list(dict.fromkeys(errors))\n\n\ndef grading_profile_is_ready(profile: GradingProfile) -> bool:\n    return bool(profile.is_active and not grading_profile_errors(profile))\n\n\ndef _scope_matches(profile, offering, stage, level, program) -> bool:\n    return bool(\n        (profile.campus_id is None or profile.campus_id == offering.campus_id)\n        and (profile.stage_id is None or (stage and profile.stage_id == stage.pk))\n        and (profile.level_id is None or (level and profile.level_id == level.pk))\n        and (profile.program_id is None or (program and profile.program_id == program.pk))\n        and (profile.academic_term_id is None or profile.academic_term_id == offering.term_id)\n    )\n\n\ndef _specificity(profile, offering, stage, level, program) -> tuple:\n    exact = sum(\n        (\n            bool(profile.campus_id and profile.campus_id == offering.campus_id),\n            bool(profile.stage_id and stage and profile.stage_id == stage.pk),\n            bool(profile.level_id and level and profile.level_id == level.pk),\n            bool(profile.program_id and program and profile.program_id == program.pk),\n            bool(profile.academic_term_id and profile.academic_term_id == offering.term_id),\n        )\n    )\n    return profile.priority, exact, int(profile.is_default), profile.pk or 0\n\n\ndef resolve_grading_profile(offering) -> GradingProfile | None:\n    level = offering_level(offering)\n    program = offering_program(offering)\n    stage = offering_stage(offering)\n    candidates = GradingProfile.objects.filter(is_active=True).select_related(\n        "grading_scale", "campus", "stage", "level", "program", "academic_term"\n    ).prefetch_related("grading_scale__ranges")\n    matched = [\n        profile\n        for profile in candidates\n        if _scope_matches(profile, offering, stage, level, program)\n        and grading_profile_is_ready(profile)\n    ]\n    return max(matched, key=lambda item: _specificity(item, offering, stage, level, program)) if matched else None\n\n\ndef grade_for_percentage(value, profile: GradingProfile | None) -> tuple[str, str]:\n    if value is None:\n        return "-", "Not graded"\n    if not profile or not grading_profile_is_ready(profile):\n        return "", ""\n    percentage = _to_decimal(value)\n    for band in profile.grading_scale.ranges.order_by("-min_score", "-max_score", "pk"):\n        if band.min_score <= percentage <= band.max_score:\n            return band.grade, band.remark or band.grade\n    fallback_bands = (\n        (Decimal("80"), "A", "Excellent"),\n        (Decimal("70"), "B", "Very good"),\n        (Decimal("60"), "C", "Good"),\n        (Decimal("50"), "D", "Fair"),\n        (Decimal("0"), "F", "Needs improvement"),\n    )\n    for minimum, letter, remark in fallback_bands:\n        if percentage >= minimum:\n            return letter, remark\n    return "-", "Not graded"\n\n\ndef rounded_percentage(value, profile: GradingProfile | None):\n    if value is None:\n        return None\n    places = profile.decimal_places if profile else 2\n    quantum = Decimal("1").scaleb(-places)\n    return _to_decimal(value).quantize(quantum, rounding=ROUND_HALF_UP)\n\n\ndef report_rule_for_profile(profile: GradingProfile | None) -> ReportRule | None:\n    if not profile:\n        return None\n    try:\n        return profile.report_rule\n    except ReportRule.DoesNotExist:\n        return None\n\n\ndef _course_percentage(course):\n    if course.scheme:\n        return course.weighted_percentage\n    return course.weighted_percentage if course.weighted_percentage is not None else course.simple_percentage\n\n\ndef select_report_profile(course_results) -> GradingProfile | None:\n    profiles = [item.grading_profile for item in course_results if getattr(item, "grading_profile", None)]\n    if not profiles:\n        return None\n    counts = Counter(profile.pk for profile in profiles)\n    profile_by_id = {profile.pk: profile for profile in profiles}\n    return max(\n        profile_by_id.values(),\n        key=lambda profile: (counts[profile.pk], profile.priority, int(profile.is_default), profile.pk),\n    )\n\n\ndef calculate_report_summary(course_results) -> dict:\n    profile = select_report_profile(course_results)\n    policy = profile.incomplete_result_policy if profile else GradingProfile.EXCLUDE_INCOMPLETE\n    rows = []\n    is_complete = True\n    for course in course_results:\n        value = _course_percentage(course)\n        if value is None or not course.is_complete:\n            is_complete = False\n            if policy == GradingProfile.REQUIRE_COMPLETE:\n                return {\n                    "profile": profile,\n                    "overall_percentage": None,\n                    "passed_course_count": 0,\n                    "failed_course_count": 0,\n                    "is_complete": False,\n                    "promotion_status": "INCOMPLETE",\n                }\n            if policy == GradingProfile.ZERO_INCOMPLETE:\n                value = Decimal("0")\n            else:\n                continue\n        weight = Decimal("1")\n        if profile and profile.overall_aggregation == GradingProfile.CREDIT_WEIGHTED:\n            weight = Decimal(str(course.offering.course.credits or 1))\n        rows.append((Decimal(str(value)), weight))\n\n    overall = None\n    if rows:\n        denominator = sum((weight for _, weight in rows), Decimal("0"))\n        if denominator > 0:\n            overall = sum((value * weight for value, weight in rows), Decimal("0")) / denominator\n            overall = rounded_percentage(overall, profile)\n\n    threshold = profile.pass_percentage if profile else Decimal("50")\n    completed_values = [\n        _course_percentage(course)\n        for course in course_results\n        if _course_percentage(course) is not None and course.is_complete\n    ]\n    passed = sum(1 for value in completed_values if value >= threshold)\n    failed = sum(1 for value in completed_values if value < threshold)\n\n    promotion_status = ""\n    if profile and profile.promotion_percentage is not None:\n        required_courses = profile.minimum_passed_courses or 0\n        if overall is None:\n            promotion_status = "INCOMPLETE"\n        elif overall >= profile.promotion_percentage and passed >= required_courses:\n            promotion_status = "PROMOTED"\n        else:\n            promotion_status = "REVIEW"\n\n    return {\n        "profile": profile,\n        "overall_percentage": overall,\n        "passed_course_count": passed,\n        "failed_course_count": failed,\n        "is_complete": is_complete,\n        "promotion_status": promotion_status,\n    }\n\n\ndef bootstrap_default_grading_profile(*, dry_run=False) -> dict:\n    default_scale = GradingScale.objects.filter(is_active=True, is_default=True).prefetch_related("ranges").first()\n    summary = {"profile_created": 0, "rule_created": 0, "profile_existing": 0, "scale_available": bool(default_scale)}\n    if not default_scale or grading_scale_errors(default_scale):\n        return summary\n    existing = GradingProfile.objects.filter(code="DEFAULT-GRADING").first()\n    if existing:\n        summary["profile_existing"] = 1\n        if not hasattr(existing, "report_rule"):\n            summary["rule_created"] = 1\n            if not dry_run:\n                ReportRule.objects.create(grading_profile=existing)\n        return summary\n    summary["profile_created"] = 1\n    summary["rule_created"] = 1\n    if not dry_run:\n        profile = GradingProfile.objects.create(\n            code="DEFAULT-GRADING",\n            name=f"Default {default_scale.name}",\n            grading_scale=default_scale,\n            is_default=True,\n            is_active=True,\n        )\n        ReportRule.objects.create(grading_profile=profile)\n    return summary\n\n\ndef grading_framework_readiness() -> dict:\n    profiles = list(\n        GradingProfile.objects.select_related(\n            "grading_scale", "campus", "stage", "level", "program", "academic_term"\n        ).prefetch_related("grading_scale__ranges")\n    )\n    invalid = [{"profile": profile, "errors": grading_profile_errors(profile)} for profile in profiles]\n    invalid = [row for row in invalid if row["errors"]]\n    active_profiles = [profile for profile in profiles if profile.is_active]\n    missing_rules = sum(1 for profile in active_profiles if not hasattr(profile, "report_rule"))\n    checks = {\n        "profile_available": bool(active_profiles),\n        "profiles_valid": not invalid,\n        "report_rules_available": missing_rules == 0,\n    }\n    return {\n        "ready": all(checks.values()),\n        "checks": checks,\n        "profile_count": len(profiles),\n        "active_profile_count": len(active_profiles),\n        "invalid_profiles": invalid,\n        "invalid_profile_count": len(invalid),\n        "missing_report_rule_count": missing_rules,\n        "default_scale_available": GradingScale.objects.filter(is_active=True, is_default=True).exists(),\n    }\n')
write('apps/tenant/assessments/grading_forms.py', '\nfrom django import forms\n\nfrom .grading_services import grading_profile_errors\nfrom .models import GradingProfile, ReportRule, normalize_assessment_code\n\n\nclass GradingProfileForm(forms.ModelForm):\n    class Meta:\n        model = GradingProfile\n        fields = [\n            "code",\n            "name",\n            "description",\n            "grading_scale",\n            "campus",\n            "stage",\n            "level",\n            "program",\n            "academic_term",\n            "overall_aggregation",\n            "incomplete_result_policy",\n            "pass_percentage",\n            "promotion_percentage",\n            "minimum_passed_courses",\n            "decimal_places",\n            "priority",\n            "is_default",\n            "is_active",\n        ]\n        widgets = {"description": forms.Textarea(attrs={"rows": 3})}\n        help_texts = {\n            "priority": "Higher priority wins when more than one valid profile matches.",\n            "is_default": "Used as a tie-breaker after priority and scope specificity.",\n            "promotion_percentage": "Leave blank to disable automatic promotion or progression status.",\n            "minimum_passed_courses": "Optional minimum number of passed courses required for promotion.",\n        }\n\n    def clean_code(self):\n        return normalize_assessment_code(self.cleaned_data.get("code"))\n\n    def clean(self):\n        cleaned = super().clean()\n        if self.instance:\n            for field, value in cleaned.items():\n                if hasattr(self.instance, field):\n                    setattr(self.instance, field, value)\n            errors = grading_profile_errors(self.instance)\n            if errors:\n                raise forms.ValidationError(errors)\n        return cleaned\n\n\nclass ReportRuleForm(forms.ModelForm):\n    class Meta:\n        model = ReportRule\n        fields = [\n            "report_title",\n            "result_label",\n            "promotion_label",\n            "show_percentage",\n            "show_grade",\n            "show_remark",\n            "show_published_scores",\n            "show_assessment_details",\n            "show_component_breakdown",\n            "show_promotion_status",\n            "show_teacher_comments",\n            "show_head_comments",\n        ]\n')
write('apps/tenant/assessments/grading_views.py', '\nfrom django.contrib import messages\nfrom django.shortcuts import get_object_or_404, redirect, render\n\nfrom apps.tenant.portals.permissions import role_required\nfrom apps.tenant.users.models import Role\n\nfrom .grading_forms import GradingProfileForm, ReportRuleForm\nfrom .grading_services import (\n    bootstrap_default_grading_profile,\n    grading_framework_readiness,\n    grading_profile_errors,\n)\nfrom .models import GradingProfile, ReportRule\n\n\n@role_required(Role.ADMIN)\ndef grading_framework_dashboard(request):\n    if request.method == "POST" and request.POST.get("action") == "bootstrap":\n        summary = bootstrap_default_grading_profile(dry_run=False)\n        if summary["profile_created"]:\n            messages.success(request, "Default grading profile and report rules created.")\n        elif summary["profile_existing"]:\n            messages.success(request, "Default grading profile already exists; missing report rules were repaired.")\n        else:\n            messages.warning(\n                request,\n                "No valid active default grading scale is available. Configure its grade ranges first.",\n            )\n        return redirect("admin_grading_framework_dashboard")\n\n    readiness = grading_framework_readiness()\n    profiles = GradingProfile.objects.select_related(\n        "grading_scale", "campus", "stage", "level", "program", "academic_term"\n    ).prefetch_related("grading_scale__ranges")\n    rows = [{"profile": profile, "errors": grading_profile_errors(profile)} for profile in profiles]\n    return render(\n        request,\n        "portals/admin/assessments/grading/dashboard.html",\n        {"readiness": readiness, "profile_rows": rows},\n    )\n\n\n@role_required(Role.ADMIN)\ndef grading_profile_create(request):\n    if request.method == "POST":\n        form = GradingProfileForm(request.POST)\n        if form.is_valid():\n            profile = form.save()\n            ReportRule.objects.get_or_create(grading_profile=profile)\n            messages.success(request, "Grading profile created with default report rules.")\n            return redirect("admin_grading_framework_dashboard")\n    else:\n        form = GradingProfileForm()\n    return render(\n        request,\n        "portals/admin/assessments/framework/form.html",\n        {\n            "form": form,\n            "title": "Add grading profile",\n            "back_url_name": "admin_grading_framework_dashboard",\n        },\n    )\n\n\n@role_required(Role.ADMIN)\ndef grading_profile_edit(request, pk: int):\n    profile = get_object_or_404(GradingProfile, pk=pk)\n    if request.method == "POST":\n        form = GradingProfileForm(request.POST, instance=profile)\n        if form.is_valid():\n            form.save()\n            messages.success(request, "Grading profile updated.")\n            return redirect("admin_grading_framework_dashboard")\n    else:\n        form = GradingProfileForm(instance=profile)\n    return render(\n        request,\n        "portals/admin/assessments/framework/form.html",\n        {\n            "form": form,\n            "title": "Edit grading profile",\n            "back_url_name": "admin_grading_framework_dashboard",\n        },\n    )\n\n\n@role_required(Role.ADMIN)\ndef report_rule_edit(request, profile_pk: int):\n    profile = get_object_or_404(GradingProfile, pk=profile_pk)\n    rule, _ = ReportRule.objects.get_or_create(grading_profile=profile)\n    if request.method == "POST":\n        form = ReportRuleForm(request.POST, instance=rule)\n        if form.is_valid():\n            form.save()\n            messages.success(request, "Report-card rules updated.")\n            return redirect("admin_grading_framework_dashboard")\n    else:\n        form = ReportRuleForm(instance=rule)\n    return render(\n        request,\n        "portals/admin/assessments/framework/form.html",\n        {\n            "form": form,\n            "title": f"Report rules — {profile.name}",\n            "back_url_name": "admin_grading_framework_dashboard",\n        },\n    )\n')
write('apps/tenant/assessments/management/commands/bootstrap_grading_profiles.py', '\nfrom django.core.management.base import BaseCommand, CommandError\nfrom django_tenants.utils import tenant_context\n\nfrom apps.public.tenants.models import Tenant\n\nfrom ...grading_services import bootstrap_default_grading_profile\n\n\nclass Command(BaseCommand):\n    help = "Create a safe default Phase 4 grading profile from each tenant\'s active default grading scale."\n\n    def add_arguments(self, parser):\n        parser.add_argument("--schema", help="Run for one tenant schema only.")\n        parser.add_argument("--dry-run", action="store_true", help="Report intended changes without writing data.")\n\n    def handle(self, *args, **options):\n        schema = (options.get("schema") or "").strip()\n        tenants = Tenant.objects.exclude(schema_name="public").order_by("schema_name")\n        if schema:\n            tenants = tenants.filter(schema_name=schema)\n            if not tenants.exists():\n                raise CommandError(f"Tenant schema \'{schema}\' was not found.")\n        dry_run = bool(options.get("dry_run"))\n        for tenant in tenants:\n            with tenant_context(tenant):\n                summary = bootstrap_default_grading_profile(dry_run=dry_run)\n                self.stdout.write(self.style.MIGRATE_HEADING(f"Tenant: {tenant.schema_name}"))\n                self.stdout.write(\n                    "Default scale available: "\n                    f"{\'yes\' if summary[\'scale_available\'] else \'no\'}; "\n                    f"profiles to create: {summary[\'profile_created\']}; "\n                    f"existing: {summary[\'profile_existing\']}; "\n                    f"report rules to create: {summary[\'rule_created\']}."\n                )\n                if not summary["scale_available"]:\n                    self.stdout.write(\n                        self.style.WARNING(\n                            "No active default grading scale is available. No grading profile was created."\n                        )\n                    )\n                else:\n                    self.stdout.write(\n                        self.style.SUCCESS(\n                            "Dry run complete; no data changed."\n                            if dry_run\n                            else "Grading profile bootstrap complete. Existing scales, marks and grades were not changed."\n                        )\n                    )\n')
write('apps/tenant/assessments/management/commands/audit_grading_profiles.py', '\nfrom django.core.management.base import BaseCommand, CommandError\nfrom django_tenants.utils import tenant_context\n\nfrom apps.public.tenants.models import Tenant\n\nfrom ...grading_services import grading_framework_readiness\n\n\nclass Command(BaseCommand):\n    help = "Run a read-only Phase 4 grading-profile and report-rule audit for one or all tenants."\n\n    def add_arguments(self, parser):\n        parser.add_argument("--schema", help="Audit one tenant schema only.")\n        parser.add_argument(\n            "--fail-on-incomplete",\n            action="store_true",\n            help="Return a non-zero exit code when Phase 4 configuration is incomplete.",\n        )\n\n    def handle(self, *args, **options):\n        schema = (options.get("schema") or "").strip()\n        tenants = Tenant.objects.exclude(schema_name="public").order_by("schema_name")\n        if schema:\n            tenants = tenants.filter(schema_name=schema)\n            if not tenants.exists():\n                raise CommandError(f"Tenant schema \'{schema}\' was not found.")\n\n        audited = 0\n        incomplete = 0\n        for tenant in tenants:\n            audited += 1\n            with tenant_context(tenant):\n                readiness = grading_framework_readiness()\n                self.stdout.write(self.style.MIGRATE_HEADING(f"Tenant: {tenant.schema_name}"))\n                self.stdout.write(\n                    f"Profiles: {readiness[\'profile_count\']}; "\n                    f"active: {readiness[\'active_profile_count\']}; "\n                    f"invalid: {readiness[\'invalid_profile_count\']}; "\n                    f"missing report rules: {readiness[\'missing_report_rule_count\']}."\n                )\n                if readiness["ready"]:\n                    self.stdout.write(self.style.SUCCESS("Phase 4 grading framework is structurally ready."))\n                else:\n                    incomplete += 1\n                    self.stdout.write(\n                        self.style.WARNING(\n                            "Phase 4 needs attention. No grading scales, score records or historical grades were changed."\n                        )\n                    )\n        self.stdout.write(f"Audit complete: {audited} tenant(s), {incomplete} incomplete. No data was changed.")\n        if options.get("fail_on_incomplete") and incomplete:\n            raise CommandError(f"Grading framework audit found {incomplete} incomplete tenant(s).")\n')
write('apps/tenant/assessments/test_phase4_grading.py', '\nfrom decimal import Decimal\n\nfrom django.test import TestCase\n\nfrom apps.tenant.academics.models import (\n    AcademicTerm,\n    AcademicYear,\n    ClassGroup,\n    Course,\n    CourseOffering,\n    Enrollment,\n    GradeRange,\n    GradingScale,\n    Level,\n    Stream,\n)\nfrom apps.tenant.orgsettings.models import Campus\nfrom apps.tenant.orgsettings.services import get_or_create_organization\nfrom apps.tenant.students.models import StudentProfile\n\nfrom .grading_services import (\n    calculate_report_summary,\n    grading_framework_readiness,\n    resolve_grading_profile,\n)\nfrom .models import Assessment, AssessmentScore, GradingProfile, ReportRule\nfrom .services import build_report_card, score_result\n\n\nclass Phase4GradingProfileTests(TestCase):\n    def setUp(self):\n        organization = get_or_create_organization()\n        self.campus = Campus.objects.filter(organization=organization).first()\n        self.year = AcademicYear.objects.create(name="2026")\n        self.term = AcademicTerm.objects.create(year=self.year, name="Term 1", order=1)\n        self.level = Level.objects.create(name="Senior One", order=1)\n        self.class_group = ClassGroup.objects.create(\n            campus=self.campus,\n            name="Senior One",\n            level=self.level,\n        )\n        self.stream = Stream.objects.create(class_group=self.class_group, name="A")\n        self.course = Course.objects.create(name="Mathematics", code="MATH", level=self.level, credits=3)\n        self.offering = CourseOffering.objects.create(\n            campus=self.campus,\n            course=self.course,\n            term=self.term,\n            class_group=self.class_group,\n        )\n        self.student = StudentProfile.objects.create(\n            campus=self.campus,\n            stream=self.stream,\n            student_id="P4-001",\n            first_name="Amina",\n            last_name="Learner",\n        )\n        Enrollment.objects.create(campus=self.campus, offering=self.offering, student=self.student)\n        self.scale = GradingScale.objects.create(name="Phase 4 Scale", is_default=True, is_active=True)\n        GradeRange.objects.create(scale=self.scale, grade="A", min_score=80, max_score=100, remark="Excellent", order=1)\n        GradeRange.objects.create(scale=self.scale, grade="B", min_score=70, max_score=79.99, remark="Very good", order=2)\n        GradeRange.objects.create(scale=self.scale, grade="C", min_score=60, max_score=69.99, remark="Good", order=3)\n        GradeRange.objects.create(scale=self.scale, grade="D", min_score=50, max_score=59.99, remark="Fair", order=4)\n        GradeRange.objects.create(scale=self.scale, grade="F", min_score=0, max_score=49.99, remark="Needs support", order=5)\n\n    def _profile(self, **overrides):\n        values = {\n            "code": "DEFAULT-GRADING",\n            "name": "Default grading",\n            "grading_scale": self.scale,\n            "is_default": True,\n            "is_active": True,\n        }\n        values.update(overrides)\n        profile = GradingProfile.objects.create(**values)\n        ReportRule.objects.create(grading_profile=profile, show_promotion_status=True)\n        return profile\n\n    def test_more_specific_profile_wins_deterministically(self):\n        self._profile()\n        specific_scale = GradingScale.objects.create(name="Senior One Scale", is_active=True)\n        GradeRange.objects.create(scale=specific_scale, grade="DIST", min_score=75, max_score=100, remark="Distinction")\n        GradeRange.objects.create(scale=specific_scale, grade="PASS", min_score=0, max_score=74.99, remark="Pass")\n        specific = self._profile(\n            code="S1-GRADING",\n            name="Senior One grading",\n            grading_scale=specific_scale,\n            level=self.level,\n            priority=10,\n        )\n\n        self.assertEqual(resolve_grading_profile(self.offering), specific)\n\n    def test_score_result_uses_matching_existing_grading_scale(self):\n        profile = self._profile(level=self.level)\n        assessment = Assessment.objects.create(\n            offering=self.offering,\n            name="End of Term",\n            max_score=100,\n            is_published=True,\n        )\n        score = AssessmentScore.objects.create(assessment=assessment, student=self.student, score=75)\n\n        result = score_result(assessment, score)\n\n        self.assertEqual(result.grade, "B")\n        self.assertEqual(result.remark, "Very good")\n        self.assertEqual(resolve_grading_profile(self.offering), profile)\n\n    def test_current_default_grade_bands_remain_fallback_without_profile(self):\n        assessment = Assessment.objects.create(\n            offering=self.offering,\n            name="Test",\n            max_score=100,\n            is_published=True,\n        )\n        score = AssessmentScore.objects.create(assessment=assessment, student=self.student, score=85)\n\n        result = score_result(assessment, score)\n\n        self.assertEqual(result.grade, "A")\n        self.assertEqual(result.remark, "Excellent")\n\n    def test_report_card_applies_promotion_and_report_rules_without_rewriting_score(self):\n        profile = self._profile(\n            level=self.level,\n            pass_percentage=50,\n            promotion_percentage=70,\n            minimum_passed_courses=1,\n        )\n        assessment = Assessment.objects.create(\n            offering=self.offering,\n            name="Final",\n            max_score=100,\n            is_published=True,\n        )\n        score = AssessmentScore.objects.create(assessment=assessment, student=self.student, score=75)\n\n        report = build_report_card(self.student)\n        score.refresh_from_db()\n\n        self.assertEqual(report.grading_profile, profile)\n        self.assertEqual(report.report_rule, profile.report_rule)\n        self.assertEqual(report.overall_percentage, Decimal("75.00"))\n        self.assertEqual(report.overall_grade, "B")\n        self.assertEqual(report.promotion_status, "PROMOTED")\n        self.assertEqual(score.score, Decimal("75"))\n\n    def test_require_complete_policy_keeps_report_incomplete(self):\n        self._profile(\n            level=self.level,\n            incomplete_result_policy=GradingProfile.REQUIRE_COMPLETE,\n        )\n        Assessment.objects.create(\n            offering=self.offering,\n            name="Missing result",\n            max_score=100,\n            is_published=True,\n        )\n\n        report = build_report_card(self.student)\n\n        self.assertIsNone(report.overall_percentage)\n        self.assertFalse(report.is_complete)\n\n    def test_readiness_reports_valid_profile_and_rule(self):\n        self._profile(level=self.level)\n        readiness = grading_framework_readiness()\n        self.assertTrue(readiness["ready"])\n        self.assertEqual(readiness["invalid_profile_count"], 0)\n        self.assertEqual(readiness["missing_report_rule_count"], 0)\n')
write('apps/tenant/assessments/test_phase4_views.py', '\nfrom django.contrib.auth import get_user_model\nfrom django.test import TestCase\nfrom django.urls import reverse\n\nfrom apps.tenant.academics.models import GradeRange, GradingScale\nfrom apps.tenant.orgsettings.models import Campus, OrganizationProfile\nfrom apps.tenant.users.models import Role, UserRole\n\nfrom .models import GradingProfile, ReportRule\n\n\nclass Phase4GradingFrameworkViewTests(TestCase):\n    def setUp(self):\n        self.organization = OrganizationProfile.objects.create(name="Phase 4 View School")\n        self.campus = Campus.objects.create(\n            organization=self.organization,\n            name="Main Campus",\n            is_default=True,\n            is_active=True,\n        )\n        self.scale = GradingScale.objects.create(name="Default Scale", is_default=True, is_active=True)\n        GradeRange.objects.create(scale=self.scale, grade="A", min_score=80, max_score=100, remark="Excellent")\n        GradeRange.objects.create(scale=self.scale, grade="B", min_score=70, max_score=79.99, remark="Very good")\n        GradeRange.objects.create(scale=self.scale, grade="C", min_score=60, max_score=69.99, remark="Good")\n        GradeRange.objects.create(scale=self.scale, grade="D", min_score=50, max_score=59.99, remark="Fair")\n        GradeRange.objects.create(scale=self.scale, grade="F", min_score=0, max_score=49.99, remark="Needs support")\n        self.superuser = get_user_model().objects.create_superuser(\n            username="phase4admin",\n            email="phase4@example.com",\n            password="test-password",\n        )\n        self.client.force_login(self.superuser)\n\n    def test_dashboard_is_available_to_full_administrator(self):\n        response = self.client.get(reverse("admin_grading_framework_dashboard"))\n        self.assertEqual(response.status_code, 200)\n        self.assertContains(response, "Level-specific grading and report rules")\n\n    def test_bootstrap_creates_default_profile_without_changing_scale(self):\n        response = self.client.post(\n            reverse("admin_grading_framework_dashboard"),\n            {"action": "bootstrap"},\n        )\n        self.assertEqual(response.status_code, 302)\n        profile = GradingProfile.objects.get(code="DEFAULT-GRADING")\n        self.assertEqual(profile.grading_scale, self.scale)\n        self.assertTrue(ReportRule.objects.filter(grading_profile=profile).exists())\n        self.scale.refresh_from_db()\n        self.assertTrue(self.scale.is_default)\n\n    def test_create_profile_normalizes_code(self):\n        response = self.client.post(\n            reverse("admin_grading_profile_create"),\n            {\n                "code": " senior one ",\n                "name": "Senior One",\n                "description": "",\n                "grading_scale": self.scale.pk,\n                "overall_aggregation": GradingProfile.MEAN,\n                "incomplete_result_policy": GradingProfile.EXCLUDE_INCOMPLETE,\n                "pass_percentage": "50",\n                "decimal_places": "2",\n                "priority": "10",\n                "is_active": "on",\n            },\n        )\n        self.assertEqual(response.status_code, 302)\n        self.assertTrue(GradingProfile.objects.filter(code="SENIOR-ONE").exists())\n\n    def test_campus_administrator_cannot_change_institution_wide_grading_rules(self):\n        role, _ = Role.objects.get_or_create(\n            code=Role.CAMPUS_ADMIN,\n            defaults={"name": "Campus Admin"},\n        )\n        user = get_user_model().objects.create_user(\n            username="phase4campusadmin",\n            password="test-password",\n        )\n        UserRole.objects.create(user=user, role=role, campus=self.campus)\n        self.client.force_login(user)\n\n        response = self.client.get(reverse("admin_grading_framework_dashboard"))\n\n        self.assertEqual(response.status_code, 403)\n')
write('templates/portals/admin/assessments/grading/dashboard.html', '\n{% extends \'portals/admin/base.html\' %}\n{% block title %}Grading Profiles{% endblock %}\n{% block page_title %}Grading Profiles{% endblock %}\n{% block breadcrumbs %}Configure level-specific grading scales, overall result rules and report-card presentation without changing existing marks.{% endblock %}\n{% block header_actions %}\n<a href="{% url \'admin_assessment_framework_dashboard\' %}" class="rounded-xl border border-slate-200 bg-white px-4 py-2 text-sm font-bold text-slate-700">Assessment Framework</a>\n<a href="{% url \'admin_grading_profile_create\' %}" class="rounded-xl bg-primary-600 px-4 py-2 text-sm font-bold text-white">Add Profile</a>\n{% endblock %}\n{% block content %}\n{% include "components/ui_toast.html" %}\n<div class="space-y-7">\n  <section class="rounded-3xl bg-gradient-to-br from-slate-950 via-violet-950 to-primary-800 p-6 text-white shadow-xl">\n    <div class="flex flex-col gap-5 lg:flex-row lg:items-end lg:justify-between">\n      <div><p class="text-xs font-black uppercase tracking-[0.2em] text-violet-100">Phase 4 configuration</p><h2 class="mt-2 text-3xl font-black">Level-specific grading and report rules</h2><p class="mt-3 max-w-3xl text-sm text-violet-100">Select existing grading scales by campus, education stage, level, programme and term. The current A–F rules remain the fallback whenever no valid profile matches.</p></div>\n      <div class="rounded-2xl bg-white/10 px-5 py-4 ring-1 ring-white/15"><p class="text-xs font-bold uppercase text-violet-100">Readiness</p><p class="mt-1 text-3xl font-black">{% if readiness.ready %}Ready{% else %}Needs attention{% endif %}</p></div>\n    </div>\n  </section>\n\n  <section class="grid gap-4 md:grid-cols-2 xl:grid-cols-4">\n    <div class="rounded-2xl border border-slate-200 bg-white p-5"><p class="text-xs font-black uppercase text-slate-500">Profiles</p><p class="mt-2 text-3xl font-black text-slate-950">{{ readiness.profile_count }}</p></div>\n    <div class="rounded-2xl border border-slate-200 bg-white p-5"><p class="text-xs font-black uppercase text-slate-500">Active</p><p class="mt-2 text-3xl font-black text-emerald-700">{{ readiness.active_profile_count }}</p></div>\n    <div class="rounded-2xl border border-slate-200 bg-white p-5"><p class="text-xs font-black uppercase text-slate-500">Invalid</p><p class="mt-2 text-3xl font-black {% if readiness.invalid_profile_count %}text-red-600{% else %}text-emerald-600{% endif %}">{{ readiness.invalid_profile_count }}</p></div>\n    <div class="rounded-2xl border border-slate-200 bg-white p-5"><p class="text-xs font-black uppercase text-slate-500">Missing report rules</p><p class="mt-2 text-3xl font-black {% if readiness.missing_report_rule_count %}text-amber-600{% else %}text-emerald-600{% endif %}">{{ readiness.missing_report_rule_count }}</p></div>\n  </section>\n\n  <section class="rounded-2xl border border-slate-200 bg-white p-5">\n    <div class="flex flex-col gap-3 md:flex-row md:items-center md:justify-between">\n      <div><h3 class="text-lg font-black text-slate-950">Safe default setup</h3><p class="mt-1 text-sm text-slate-500">Create one institution-default profile from the existing active default grading scale. Grade ranges, marks and stored grades are not changed.</p></div>\n      <form method="post">{% csrf_token %}<input type="hidden" name="action" value="bootstrap"><button class="rounded-xl bg-slate-950 px-4 py-2 text-sm font-black text-white">Create default profile</button></form>\n    </div>\n  </section>\n\n  <section class="rounded-2xl border border-slate-200 bg-white shadow-sm">\n    <div class="flex items-center justify-between border-b border-slate-200 p-5"><div><h3 class="text-lg font-black text-slate-950">Grading profiles</h3><p class="text-sm text-slate-500">The highest-priority, most-specific valid profile wins.</p></div><a href="{% url \'admin_grading_profile_create\' %}" class="rounded-xl bg-primary-600 px-4 py-2 text-sm font-black text-white">Add Profile</a></div>\n    <div class="overflow-x-auto">\n      <table class="min-w-full divide-y divide-slate-200">\n        <thead class="bg-slate-50"><tr><th class="px-5 py-3 text-left text-xs font-black uppercase text-slate-500">Profile</th><th class="px-5 py-3 text-left text-xs font-black uppercase text-slate-500">Scope</th><th class="px-5 py-3 text-left text-xs font-black uppercase text-slate-500">Scale</th><th class="px-5 py-3 text-left text-xs font-black uppercase text-slate-500">Rules</th><th class="px-5 py-3 text-left text-xs font-black uppercase text-slate-500">Validation</th><th class="px-5 py-3"></th></tr></thead>\n        <tbody class="divide-y divide-slate-100">\n          {% for row in profile_rows %}\n          <tr>\n            <td class="px-5 py-4"><div class="font-black text-slate-950">{{ row.profile.name }}</div><div class="text-xs text-slate-500">{{ row.profile.code }} · priority {{ row.profile.priority }}</div></td>\n            <td class="px-5 py-4 text-sm text-slate-600">{{ row.profile.scope_label }}</td>\n            <td class="px-5 py-4"><div class="font-bold text-slate-900">{{ row.profile.grading_scale }}</div><div class="text-xs text-slate-500">Pass {{ row.profile.pass_percentage }}%</div></td>\n            <td class="px-5 py-4 text-sm text-slate-600">{{ row.profile.get_overall_aggregation_display }}<br>{{ row.profile.get_incomplete_result_policy_display }}</td>\n            <td class="px-5 py-4 text-sm">{% if row.errors %}<span class="font-bold text-red-600">{{ row.errors|length }} issue{{ row.errors|length|pluralize }}</span>{% else %}<span class="font-bold text-emerald-700">Valid</span>{% endif %}</td>\n            <td class="px-5 py-4 text-right whitespace-nowrap"><a class="mr-3 text-sm font-black text-primary-700" href="{% url \'admin_grading_profile_edit\' row.profile.pk %}">Edit</a><a class="text-sm font-black text-violet-700" href="{% url \'admin_report_rule_edit\' row.profile.pk %}">Report rules</a></td>\n          </tr>\n          {% empty %}<tr><td colspan="6" class="p-8 text-center text-slate-500">No grading profiles configured yet.</td></tr>{% endfor %}\n        </tbody>\n      </table>\n    </div>\n  </section>\n</div>\n{% endblock %}\n')
write('docs/phase-4-grading-profiles.md', '\n# Phase 4 — Level-specific grading profiles and report rules\n\nPhase 4 adds an additive configuration layer around the existing grading and report-card system.\n\n## Source-of-truth guarantees\n\nThe following records remain authoritative and are not copied or rewritten:\n\n- `academics.GradingScale` and `academics.GradeRange`;\n- `assessments.AssessmentScore`;\n- `exams.ExamScore`;\n- existing assessment, examination, student and report-card routes.\n\nA `GradingProfile` only selects an existing grading scale for a matching campus, education stage, level, programme and academic term. `ReportRule` controls report-card presentation and progression status.\n\n## Resolution order\n\nOnly active, structurally valid profiles participate. Matching is deterministic:\n\n1. highest priority;\n2. most exact scope fields;\n3. default flag;\n4. profile primary key.\n\nWhen no profile matches, EduManage keeps the existing A–F grading bands and current mean-based report-card calculation.\n\n## Rollout\n\nPreview the default-profile bootstrap:\n\n```bash\npython manage.py bootstrap_grading_profiles --dry-run\n```\n\nCreate a default profile from each tenant\'s existing active default grading scale:\n\n```bash\npython manage.py bootstrap_grading_profiles\n```\n\nRun the read-only audit:\n\n```bash\npython manage.py audit_grading_profiles --fail-on-incomplete\n```\n\nAdministrators can then add narrower profiles from **Assessments → Grading Profiles**.\n\n## Report behavior\n\nProfiles may configure:\n\n- existing grading scale;\n- pass percentage;\n- mean or credit-weighted overall aggregation;\n- incomplete-course handling;\n- optional promotion percentage and minimum passed-course count;\n- decimal precision.\n\nReport rules may show or hide percentage, grade, remark, score counts, assessment detail, weighting-component breakdown and promotion status.\n\n## Rollback\n\nApplication rollback is safe because existing marks and grading scales are unchanged. Reverting the application restores the previous report-card behavior. The additive Phase 4 tables can remain unused until the migration is rolled back during a controlled maintenance window.\n')
replace('apps/tenant/assessments/models.py', 'from django.core.validators import MinValueValidator', 'from django.core.validators import MaxValueValidator, MinValueValidator')
replace('apps/tenant/assessments/models.py', '\n\nclass Assessment(models.Model):', '\n\nclass GradingProfile(models.Model):\n    MEAN = "MEAN"\n    CREDIT_WEIGHTED = "CREDIT_WEIGHTED"\n\n    OVERALL_AGGREGATION_CHOICES = (\n        (MEAN, "Mean of completed course results"),\n        (CREDIT_WEIGHTED, "Credit-weighted mean"),\n    )\n\n    EXCLUDE_INCOMPLETE = "EXCLUDE"\n    ZERO_INCOMPLETE = "ZERO"\n    REQUIRE_COMPLETE = "INCOMPLETE"\n\n    INCOMPLETE_RESULT_POLICY_CHOICES = (\n        (EXCLUDE_INCOMPLETE, "Exclude incomplete courses from the overall result"),\n        (ZERO_INCOMPLETE, "Treat incomplete courses as zero"),\n        (REQUIRE_COMPLETE, "Keep the report incomplete until every course is complete"),\n    )\n\n    code = models.CharField(max_length=48, unique=True)\n    name = models.CharField(max_length=128)\n    description = models.TextField(blank=True)\n    grading_scale = models.ForeignKey(\n        "academics.GradingScale",\n        on_delete=models.PROTECT,\n        related_name="grading_profiles",\n    )\n    campus = models.ForeignKey(\n        "orgsettings.Campus",\n        on_delete=models.SET_NULL,\n        null=True,\n        blank=True,\n        related_name="grading_profiles",\n    )\n    stage = models.ForeignKey(\n        "education_frameworks.EducationStage",\n        on_delete=models.SET_NULL,\n        null=True,\n        blank=True,\n        related_name="grading_profiles",\n    )\n    level = models.ForeignKey(\n        "academics.Level",\n        on_delete=models.SET_NULL,\n        null=True,\n        blank=True,\n        related_name="grading_profiles",\n    )\n    program = models.ForeignKey(\n        "academics.Program",\n        on_delete=models.SET_NULL,\n        null=True,\n        blank=True,\n        related_name="grading_profiles",\n    )\n    academic_term = models.ForeignKey(\n        "academics.AcademicTerm",\n        on_delete=models.SET_NULL,\n        null=True,\n        blank=True,\n        related_name="grading_profiles",\n    )\n    overall_aggregation = models.CharField(\n        max_length=24,\n        choices=OVERALL_AGGREGATION_CHOICES,\n        default=MEAN,\n    )\n    incomplete_result_policy = models.CharField(\n        max_length=16,\n        choices=INCOMPLETE_RESULT_POLICY_CHOICES,\n        default=EXCLUDE_INCOMPLETE,\n    )\n    pass_percentage = models.DecimalField(\n        max_digits=5,\n        decimal_places=2,\n        default=50,\n        validators=[MinValueValidator(Decimal("0")), MaxValueValidator(Decimal("100"))],\n    )\n    promotion_percentage = models.DecimalField(\n        max_digits=5,\n        decimal_places=2,\n        null=True,\n        blank=True,\n        validators=[MinValueValidator(Decimal("0")), MaxValueValidator(Decimal("100"))],\n    )\n    minimum_passed_courses = models.PositiveSmallIntegerField(null=True, blank=True)\n    decimal_places = models.PositiveSmallIntegerField(\n        default=2,\n        validators=[MaxValueValidator(4)],\n    )\n    priority = models.IntegerField(default=0)\n    is_default = models.BooleanField(default=False)\n    is_active = models.BooleanField(default=True)\n    settings = models.JSONField(default=dict, blank=True)\n    created_at = models.DateTimeField(auto_now_add=True)\n    updated_at = models.DateTimeField(auto_now=True)\n\n    class Meta:\n        ordering = ("-priority", "-is_default", "name")\n\n    def __str__(self) -> str:\n        return self.name\n\n    def clean(self):\n        super().clean()\n        self.code = normalize_assessment_code(self.code)\n        errors = {}\n        if self.grading_scale_id and not self.grading_scale.is_active:\n            errors["grading_scale"] = "Choose an active grading scale."\n        if self.pass_percentage is not None and not Decimal("0") <= self.pass_percentage <= Decimal("100"):\n            errors["pass_percentage"] = "Pass percentage must be between 0 and 100."\n        if (\n            self.promotion_percentage is not None\n            and not Decimal("0") <= self.promotion_percentage <= Decimal("100")\n        ):\n            errors["promotion_percentage"] = "Promotion percentage must be between 0 and 100."\n        if self.is_active:\n            duplicate = type(self).objects.filter(\n                campus_id=self.campus_id,\n                stage_id=self.stage_id,\n                level_id=self.level_id,\n                program_id=self.program_id,\n                academic_term_id=self.academic_term_id,\n                priority=self.priority,\n                is_active=True,\n            )\n            if self.pk:\n                duplicate = duplicate.exclude(pk=self.pk)\n            if duplicate.exists():\n                errors["__all__"] = "Another active grading profile has the same scope and priority."\n        if errors:\n            raise ValidationError(errors)\n\n    def save(self, *args, **kwargs):\n        self.code = normalize_assessment_code(self.code)\n        super().save(*args, **kwargs)\n\n    @property\n    def scope_label(self) -> str:\n        parts = []\n        if self.campus_id:\n            parts.append(str(self.campus))\n        if self.stage_id:\n            parts.append(str(self.stage))\n        if self.level_id:\n            parts.append(str(self.level))\n        if self.program_id:\n            parts.append(str(self.program))\n        if self.academic_term_id:\n            parts.append(str(self.academic_term))\n        return " · ".join(parts) if parts else "Institution default"\n\n\nclass ReportRule(models.Model):\n    grading_profile = models.OneToOneField(\n        GradingProfile,\n        on_delete=models.CASCADE,\n        related_name="report_rule",\n    )\n    report_title = models.CharField(max_length=128, blank=True)\n    result_label = models.CharField(max_length=48, default="Result")\n    promotion_label = models.CharField(max_length=48, default="Progression")\n    show_percentage = models.BooleanField(default=True)\n    show_grade = models.BooleanField(default=True)\n    show_remark = models.BooleanField(default=True)\n    show_published_scores = models.BooleanField(default=True)\n    show_assessment_details = models.BooleanField(default=True)\n    show_component_breakdown = models.BooleanField(default=True)\n    show_promotion_status = models.BooleanField(default=False)\n    show_teacher_comments = models.BooleanField(default=True)\n    show_head_comments = models.BooleanField(default=True)\n    settings = models.JSONField(default=dict, blank=True)\n    updated_at = models.DateTimeField(auto_now=True)\n\n    def __str__(self) -> str:\n        return f"Report rules — {self.grading_profile}"\n\n\nclass Assessment(models.Model):')
