replace('apps/tenant/assessments/services.py', 'def score_result(assessment: Assessment, score: AssessmentScore | None) -> ScoreResult:\n    value = score.score if score else None\n    pct = percentage(value, assessment.max_score)\n    grade, remark = grade_for_percentage(pct)\n    return ScoreResult(\n', 'def score_result(assessment: Assessment, score: AssessmentScore | None) -> ScoreResult:\n    value = score.score if score else None\n    pct = percentage(value, assessment.max_score)\n    profile = resolve_grading_profile(assessment.offering)\n    grade, remark = (\n        configured_grade_for_percentage(pct, profile)\n        if profile\n        else grade_for_percentage(pct)\n    )\n    return ScoreResult(\n')
