replace('apps/tenant/assessments/services.py', '    completed_course_percentages = []\n    for result in course_results:\n        if result.scheme:\n            value = result.weighted_percentage\n        else:\n            value = result.weighted_percentage if result.weighted_percentage is not None else result.simple_percentage\n        if value is not None:\n            completed_course_percentages.append(value)\n    overall_percentage = None\n    if completed_course_percentages:\n        overall_percentage = quantize_percent(\n            sum(completed_course_percentages, Decimal("0")) / Decimal(len(completed_course_percentages))\n        )\n    overall_grade, overall_remark = grade_for_percentage(overall_percentage)\n    return ReportCard(\n        student=student,\n        course_results=course_results,\n        overall_percentage=overall_percentage,\n        overall_grade=overall_grade,\n        overall_remark=overall_remark,\n        published_assessment_count=sum(result.assessment_count for result in course_results),\n        completed_assessment_count=sum(result.completed_count for result in course_results),\n    )\n', '    summary = calculate_report_summary(course_results)\n    grading_profile = summary["profile"]\n    overall_percentage = summary["overall_percentage"]\n    overall_grade, overall_remark = (\n        configured_grade_for_percentage(overall_percentage, grading_profile)\n        if grading_profile\n        else grade_for_percentage(overall_percentage)\n    )\n    return ReportCard(\n        student=student,\n        course_results=course_results,\n        overall_percentage=overall_percentage,\n        overall_grade=overall_grade,\n        overall_remark=overall_remark,\n        published_assessment_count=sum(result.assessment_count for result in course_results),\n        completed_assessment_count=sum(result.completed_count for result in course_results),\n        grading_profile=grading_profile,\n        report_rule=report_rule_for_profile(grading_profile),\n        promotion_status=summary["promotion_status"],\n        passed_course_count=summary["passed_course_count"],\n        failed_course_count=summary["failed_course_count"],\n        is_complete=summary["is_complete"],\n    )\n')
