replace('templates/portals/results/_report_card_body.html', '<div class="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">\n', '{% if report.grading_profile %}\n<div class="mb-5 rounded-2xl border border-violet-200 bg-violet-50 p-4">\n  <div class="flex flex-col gap-2 md:flex-row md:items-center md:justify-between">\n    <div><p class="text-xs font-black uppercase tracking-wider text-violet-700">Grading profile</p><p class="font-black text-violet-950">{{ report.grading_profile.name }} · {{ report.grading_profile.grading_scale }}</p></div>\n    {% if report.report_rule and report.report_rule.show_promotion_status and report.promotion_status %}<span class="rounded-full bg-white px-4 py-2 text-sm font-black text-violet-800 ring-1 ring-violet-200">{{ report.report_rule.promotion_label }}: {{ report.promotion_status }}</span>{% endif %}\n  </div>\n</div>\n{% endif %}\n<div class="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">\n')
